CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), role TEXT, name TEXT NOT NULL, phone TEXT UNIQUE NOT NULL, email TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, id_number TEXT NOT NULL, trades TEXT[] DEFAULT '{}', bank_code TEXT, account_number TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS jobs (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), client_id UUID REFERENCES users(id), worker_id UUID REFERENCES users(id), title TEXT NOT NULL, trade TEXT NOT NULL, description TEXT, location TEXT, budget NUMERIC NOT NULL, is_emergency BOOLEAN DEFAULT false, emergency_surcharge NUMERIC DEFAULT 0, status TEXT DEFAULT 'open', created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS milestones (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), job_id UUID REFERENCES jobs(id), worker_id UUID REFERENCES users(id), amount NUMERIC NOT NULL, description TEXT, proof_urls TEXT[] DEFAULT '{}', status TEXT DEFAULT 'pending', created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS transactions (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), user_id UUID REFERENCES users(id), job_id UUID, milestone_id UUID, amount NUMERIC, type TEXT, reference TEXT UNIQUE, status TEXT DEFAULT 'pending', created_at TIMESTAMPTZ DEFAULT NOW());
